import { UserCircle } from "lucide-react"
import { Avatar, AvatarFallback, AvatarImage } from "@/shadcn/components/ui/avatar"
import { cn } from "@/shadcn/lib/utils"

interface UserAvatarProps {
  userId?: string | null;
  firstName?: string | null;
  lastName?: string | null;
  /** Which API size to request. Defaults to "thumbnail" (64×64). */
  pictureSize?: "thumbnail" | "profile";
  /** Append a cache-bust key when a new picture has been uploaded. null = no picture, skip cache-bust param. */
  cacheKey?: number | null;
  className?: string;
  fallbackClassName?: string;
}

export function UserAvatar({
  userId,
  firstName,
  lastName,
  pictureSize = "thumbnail",
  cacheKey,
  className,
  fallbackClassName,
}: UserAvatarProps) {
  const initials = [firstName?.[0], lastName?.[0]].filter(Boolean).join("").toUpperCase();

  const src = userId
    ? `${import.meta.env.VITE_API_BASE_URL}/account/user-profile-picture/${userId}/${pictureSize}${cacheKey != null ? `?v=${cacheKey}` : ""}`
    : undefined;

  return (
    <Avatar className={className}>
      {src && <AvatarImage src={src} alt="" />}
      <AvatarFallback className={cn("text-xs font-semibold", fallbackClassName)}>
        {initials || <UserCircle className="size-1/2 text-muted-foreground/50" />}
      </AvatarFallback>
    </Avatar>
  )
}
